SELECT 
FROM timesheet t
LEFT JOIN engineer e ON e.id = t.engineer_id AND e.deleted = 0
LEFT JOIN project p ON p.id = t.project_id AND p.deleted = 0
LEFT JOIN project_task pt ON pt.id = t.task_id AND pt.deleted = 0
LEFT JOIN sys_user approver ON approver.id = t.approver_id AND approver.deleted = 0

    t.deleted = 0

        AND t.engineer_id = #{query.engineerId}


        AND t.project_id = #{query.projectId}


        AND t.task_id = #{query.taskId}


        AND t.status = #{query.status}


        AND t.work_date >= #{query.workDateStart}


        AND t.work_date <= #{query.workDateEnd}


ORDER BY t.work_date DESC, t.id DESC
